from scipy.optimize import fsolve
import numpy as np

def H(r):
    return 8537 * np.exp(-r / 8619)

def compute_r(lat_deg):
    """Dome radius from Polaris elevation = latitude"""
    elev = np.radians(lat_deg)
    def eq(r): return r * np.tan(elev) - H(r)
    return float(fsolve(eq, 5000)[0])

def dome_distance(lat1, lon1, lat2, lon2):
    """V12 distance between two northern hemisphere cities"""
    r1 = compute_r(lat1)
    r2 = compute_r(lat2)
    dt = np.radians(lon2 - lon1) * 0.9941
    return np.sqrt(r1**2 + r2**2 - 2*r1*r2*np.cos(dt))

# Example: London to Oslo
